/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
   EL SEXTANTE DIGITAL ΓÇö instrumento n├íutico de lat├│n siglo XVIII
   pose├¡do por un radar militar de f├│sforo verde.
   ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */

:root {
  --abyss: #050a0e;
  --abyss-panel: rgba(8, 14, 18, 0.82);
  --brass: #8a6d2f;
  --brass-bright: #d4a638;
  --brass-dark: #4a3a18;
  --phosphor: #39ff14;
  --phosphor-dim: rgba(57, 255, 20, 0.35);
  --parchment: #d8c9a3;
  --signal-red: #ff3b30;
}

.bg-abyss   { background-color: var(--abyss); }
.text-phosphor { color: var(--phosphor); }
.text-brass-bright { color: var(--brass-bright); }
.text-parchment { color: var(--parchment); }

.font-display  { font-family: 'Pirata One', cursive; }
.font-fell     { font-family: 'IM Fell English', serif; }
.font-terminal { font-family: 'VT323', monospace; }

body { font-family: 'IM Fell English', serif; }

/* ΓöÇΓöÇ C├ímara: tinte oc├⌐ano-nocturno para que estrellas y f├│sforo resalten ΓöÇΓöÇ */
#camera-tint {
  background:
    radial-gradient(circle at center, rgba(4, 8, 12, 0.42) 0%, rgba(4, 8, 12, 0.5) 50%, rgba(5, 10, 14, 0.78) 100%),
    linear-gradient(rgba(10, 25, 20, 0.3), rgba(10, 25, 20, 0.3));
  mix-blend-mode: multiply;
}

/* ΓöÇΓöÇ Vi├▒eta circular del visor ΓöÇΓöÇ */
#vignette {
  background: radial-gradient(circle at center,
    transparent 0%,
    transparent 52%,
    rgba(5, 10, 14, 0.55) 78%,
    rgba(3, 6, 8, 0.92) 100%);
}

/* ΓöÇΓöÇ Grano / ruido de pantalla vieja ΓöÇΓöÇ */
#noise-overlay {
  opacity: 0.07;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 240 240' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  animation: grain-shift 0.9s steps(4) infinite;
}
@keyframes grain-shift {
  0%   { transform: translate(0, 0); }
  25%  { transform: translate(-2%, 1%); }
  50%  { transform: translate(1%, -2%); }
  75%  { transform: translate(-1%, 2%); }
  100% { transform: translate(0, 0); }
}

/* ΓöÇΓöÇ Paneles de instrumentos: madera de camarote + herrajes de lat├│n ΓöÇΓöÇ */
.ui-panel {
  /* vetas de madera oscura + remaches de lat├│n en las 4 esquinas */
  background:
    radial-gradient(circle 4px at 7px 7px, #e8c76a 0%, #4a3a18 55%, transparent 60%),
    radial-gradient(circle 4px at calc(100% - 7px) 7px, #e8c76a 0%, #4a3a18 55%, transparent 60%),
    radial-gradient(circle 4px at 7px calc(100% - 7px), #e8c76a 0%, #4a3a18 55%, transparent 60%),
    radial-gradient(circle 4px at calc(100% - 7px) calc(100% - 7px), #e8c76a 0%, #4a3a18 55%, transparent 60%),
    repeating-linear-gradient(93deg,
      rgba(62, 40, 20, 0.55) 0px, rgba(42, 27, 13, 0.55) 7px,
      rgba(54, 34, 16, 0.55) 13px, rgba(38, 24, 11, 0.55) 21px),
    linear-gradient(160deg, rgba(46, 30, 16, 0.92), rgba(24, 15, 8, 0.94));
  border: 2px solid var(--brass);
  outline: 1px solid rgba(30, 19, 9, 0.9);
  border-radius: 5px;
  box-shadow:
    inset 0 0 0 3px rgba(20, 12, 5, 0.8),
    inset 0 0 0 4px rgba(212, 166, 56, 0.25),
    inset 0 0 28px rgba(0, 0, 0, 0.75),
    0 3px 14px rgba(0, 0, 0, 0.85);
  position: relative;
  backdrop-filter: blur(2px);
}

.panel-title {
  font-family: 'Pirata One', cursive;
  color: var(--parchment);
  font-size: 0.95rem;
  letter-spacing: 0.14em;
  margin-bottom: 0.3rem;
  text-shadow: 0 0 8px rgba(212, 166, 56, 0.35), 0 2px 2px #000;
}

/* ΓöÇΓöÇ Botones: placa de lat├│n sobre madera ΓöÇΓöÇ */
.brass-btn {
  font-family: 'VT323', monospace;
  font-size: 0.95rem;
  letter-spacing: 0.08em;
  color: #1a1206;
  background:
    repeating-linear-gradient(45deg, rgba(255, 240, 200, 0.07) 0 2px, transparent 2px 5px),
    linear-gradient(180deg, var(--brass-bright) 0%, var(--brass) 55%, var(--brass-dark) 100%);
  border: 1px solid var(--brass-dark);
  outline: 2px solid rgba(38, 24, 11, 0.9);
  border-radius: 3px;
  padding: 0.3rem 0.7rem;
  cursor: pointer;
  text-shadow: 0 1px 0 rgba(255, 235, 180, 0.5);
  box-shadow: inset 0 1px 0 rgba(255, 240, 200, 0.55), 0 2px 4px rgba(0, 0, 0, 0.7);
  transition: transform 0.08s ease, filter 0.15s ease;
}
.brass-btn:hover  { filter: brightness(1.15); }
.brass-btn:active { transform: translateY(1px); }
.brass-btn.btn-off { filter: grayscale(0.7) brightness(0.7); }

.brass-btn-big {
  font-family: 'Pirata One', cursive;
  font-size: 1.6rem;
  letter-spacing: 0.06em;
  color: #1a1206;
  background: linear-gradient(180deg, #e8bc4a 0%, var(--brass-bright) 45%, var(--brass) 100%);
  border: 2px solid var(--brass-dark);
  border-radius: 6px;
  padding: 0.55rem 2.2rem;
  cursor: pointer;
  box-shadow:
    inset 0 2px 0 rgba(255, 245, 210, 0.6),
    0 0 24px rgba(212, 166, 56, 0.35),
    0 4px 10px rgba(0, 0, 0, 0.8);
  transition: transform 0.1s ease, box-shadow 0.2s ease;
}
.brass-btn-big:hover {
  transform: scale(1.04);
  box-shadow:
    inset 0 2px 0 rgba(255, 245, 210, 0.6),
    0 0 42px rgba(212, 166, 56, 0.6),
    0 4px 12px rgba(0, 0, 0, 0.8);
}

/* ΓöÇΓöÇ Bot├│n flotante de calibraci├│n de sensores ΓöÇΓöÇ */
.calibrate-btn {
  top: max(0.75rem, env(safe-area-inset-top));
  left: 50%;
  transform: translateX(-50%);
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: 'Pirata One', cursive;
  font-size: 1.15rem;
  letter-spacing: 0.05em;
  color: #1a1206;
  background: linear-gradient(180deg, #e8bc4a 0%, var(--brass-bright) 45%, var(--brass) 100%);
  border: 2px solid var(--brass-dark);
  border-radius: 999px;
  padding: 0.4rem 1.3rem;
  cursor: pointer;
  box-shadow:
    inset 0 2px 0 rgba(255, 245, 210, 0.6),
    0 0 22px rgba(212, 166, 56, 0.4),
    0 4px 10px rgba(0, 0, 0, 0.8);
  /* Oculto hasta zarpar; transici├│n suave para aparecer/desaparecer */
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.6s ease, transform 0.5s ease, filter 0.2s ease;
  animation: calibrate-pulse 2.4s ease-in-out infinite;
}
body.sailing .calibrate-btn {
  opacity: 1;
  pointer-events: auto;
}
.calibrate-btn:hover  { filter: brightness(1.12); }
.calibrate-btn:active { transform: translateX(-50%) translateY(1px); }

.calibrate-btn .cal-icon { font-size: 1.35rem; line-height: 1; }

/* Estado: permiso concedido ΓÇö se torna f├│sforo antes de desvanecerse */
.calibrate-btn.sensors-ok {
  color: #04160a;
  background: linear-gradient(180deg, #7dffa0 0%, var(--phosphor) 55%, #1f9c14 100%);
  border-color: #1f9c14;
  box-shadow:
    inset 0 2px 0 rgba(220, 255, 220, 0.6),
    0 0 26px rgba(57, 255, 20, 0.55),
    0 4px 10px rgba(0, 0, 0, 0.8);
  animation: none;
}

/* Estado: permiso denegado o sin sensores ΓÇö retroceso al tim├│n manual */
.calibrate-btn.sensors-denied {
  color: #2a0704;
  background: linear-gradient(180deg, #ff8a7a 0%, var(--signal-red) 60%, #7a1710 100%);
  border-color: #7a1710;
  animation: none;
}

/* Ocultado suave una vez que los sensores quedan listos */
.calibrate-btn.hidden-fade {
  opacity: 0 !important;
  transform: translateX(-50%) translateY(-14px);
  pointer-events: none;
}

@keyframes calibrate-pulse {
  0%, 100% { box-shadow: inset 0 2px 0 rgba(255,245,210,0.6), 0 0 16px rgba(212,166,56,0.35), 0 4px 10px rgba(0,0,0,0.8); }
  50%      { box-shadow: inset 0 2px 0 rgba(255,245,210,0.6), 0 0 30px rgba(212,166,56,0.7),  0 4px 10px rgba(0,0,0,0.8); }
}

/* ΓöÇΓöÇ Overlay de inicio ΓöÇΓöÇ */
#start-overlay {
  background:
    radial-gradient(ellipse at 50% 120%, rgba(20, 45, 35, 0.55), transparent 60%),
    radial-gradient(ellipse at center, rgba(5, 10, 14, 0.88) 0%, rgba(3, 6, 8, 0.97) 100%);
  transition: opacity 0.7s ease;
}
#start-overlay.fading { opacity: 0; pointer-events: none; }

.start-frame {
  /* pergamino de mapa antiguo con bordes quemados */
  border: 2px solid var(--brass);
  outline: 1px solid rgba(30, 19, 9, 0.9);
  border-radius: 6px;
  background:
    radial-gradient(circle 5px at 10px 10px, #e8c76a 0%, #4a3a18 55%, transparent 62%),
    radial-gradient(circle 5px at calc(100% - 10px) 10px, #e8c76a 0%, #4a3a18 55%, transparent 62%),
    radial-gradient(circle 5px at 10px calc(100% - 10px), #e8c76a 0%, #4a3a18 55%, transparent 62%),
    radial-gradient(circle 5px at calc(100% - 10px) calc(100% - 10px), #e8c76a 0%, #4a3a18 55%, transparent 62%),
    radial-gradient(ellipse at center, rgba(64, 46, 24, 0.55) 0%, rgba(34, 22, 11, 0.85) 75%, rgba(16, 10, 5, 0.95) 100%),
    linear-gradient(rgba(10, 14, 16, 0.9), rgba(10, 14, 16, 0.9));
  box-shadow:
    inset 0 0 0 4px rgba(20, 12, 5, 0.85),
    inset 0 0 0 5px rgba(212, 166, 56, 0.3),
    inset 0 0 90px rgba(10, 5, 2, 0.95),
    0 0 40px rgba(0, 0, 0, 0.9);
}

.title-glow {
  text-shadow:
    0 0 18px rgba(212, 166, 56, 0.45),
    0 2px 2px rgba(0, 0, 0, 0.9);
  animation: title-breathe 4s ease-in-out infinite;
}
@keyframes title-breathe {
  0%, 100% { text-shadow: 0 0 14px rgba(212, 166, 56, 0.35), 0 2px 2px rgba(0,0,0,0.9); }
  50%      { text-shadow: 0 0 30px rgba(212, 166, 56, 0.65), 0 2px 2px rgba(0,0,0,0.9); }
}

/* ΓöÇΓöÇ Terminal de f├│sforo verde ΓöÇΓöÇ */
#terminal-overlay { background: rgba(3, 6, 8, 0.7); }
#terminal-overlay.open { display: flex; }

.terminal-frame {
  background: rgba(2, 12, 4, 0.95);
  /* CRT de f├│sforo enmarcado en madera y lat├│n del camarote */
  border: 3px solid var(--brass);
  outline: 4px solid rgba(38, 24, 11, 0.95);
  border-radius: 4px;
  box-shadow:
    inset 0 0 0 1px var(--phosphor-dim),
    0 0 30px rgba(57, 255, 20, 0.25),
    0 0 0 6px rgba(20, 12, 5, 0.6),
    inset 0 0 60px rgba(0, 40, 0, 0.6);
  animation: terminal-pop 0.25s ease-out;
  position: relative;
  overflow: hidden;
}
/* scanline del CRT */
.terminal-frame::after {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(
    0deg,
    rgba(0, 0, 0, 0.18) 0px,
    rgba(0, 0, 0, 0.18) 1px,
    transparent 1px,
    transparent 3px
  );
}
.terminal-header {
  color: var(--phosphor);
  border-bottom: 1px solid var(--phosphor-dim);
  background: rgba(57, 255, 20, 0.07);
}
#terminal-body { text-shadow: 0 0 6px rgba(57, 255, 20, 0.55); }

@keyframes terminal-pop {
  from { transform: scale(0.92); opacity: 0; }
  to   { transform: scale(1); opacity: 1; }
}

/* ΓöÇΓöÇ Aparici├│n escalonada de la UI al zarpar ΓöÇΓöÇ */
.ui-panel, #panel-controls {
  opacity: 0;
  transform: translateY(10px);
}
body.sailing .ui-panel, body.sailing #panel-controls {
  animation: panel-reveal 0.6s ease-out forwards;
}
body.sailing .stagger-1 { animation-delay: 0.15s; }
body.sailing .stagger-2 { animation-delay: 0.35s; }
body.sailing .stagger-3 { animation-delay: 0.55s; }
body.sailing .stagger-4 { animation-delay: 0.75s; }
@keyframes panel-reveal {
  to { opacity: 1; transform: translateY(0); }
}

/* ΓöÇΓöÇ Carta orbital (mapamundi 2D colapsable) ΓöÇΓöÇ */
#panel-map {
  bottom: 6.5rem;                 /* apilado sobre el panel de rumbo */
  width: 268px;
  max-width: 72vw;
}
.map-head { cursor: pointer; }
.map-head .panel-title { margin-bottom: 0; }

.map-toggle {
  font-family: 'VT323', monospace;
  font-size: 1rem;
  line-height: 1;
  color: var(--brass-bright);
  background: rgba(138, 109, 47, 0.18);
  border: 1px solid var(--brass);
  border-radius: 3px;
  padding: 0 0.4rem;
  cursor: pointer;
  transition: filter 0.15s ease, transform 0.08s ease;
}
.map-toggle:hover  { filter: brightness(1.2); }
.map-toggle:active { transform: translateY(1px); }

.map-body {
  overflow: hidden;
  max-height: 200px;
  opacity: 1;
  transition: max-height 0.3s ease, opacity 0.25s ease, margin-top 0.3s ease;
  margin-top: 0.4rem;
}
#panel-map.collapsed .map-body {
  max-height: 0;
  opacity: 0;
  margin-top: 0;
}

#map-canvas {
  display: block;
  width: 100%;
  height: auto;
  border: 1px solid var(--brass);
  border-radius: 3px;
  box-shadow: inset 0 0 14px rgba(0, 0, 0, 0.7);
  image-rendering: auto;
}
.map-readout {
  margin-top: 0.3rem;
  color: var(--phosphor);
  font-size: 0.95rem;
  letter-spacing: 0.06em;
  text-align: center;
  text-shadow: 0 0 6px rgba(57, 255, 20, 0.5);
  transition: color 0.2s ease;
}
/* ISS sobre el horizonte del observador: lector en f├│sforo pleno y latente */
.map-readout.visible-now {
  color: #7dffa0;
  text-shadow: 0 0 10px rgba(57, 255, 20, 0.85);
  animation: readout-pulse 1.4s ease-in-out infinite;
}
@keyframes readout-pulse {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0.6; }
}

/* ΓöÇΓöÇ Utilidades ΓöÇΓöÇ */
.touch-none { touch-action: none; }
#sky-canvas { cursor: grab; }
#sky-canvas.dragging { cursor: grabbing; }

/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
   starfield.js ΓÇö Estado global, proyecci├│n Az/El ΓåÆ canvas,
   visor del sextante, br├║jula perimetral y 150 estrellas.
   ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */

'use strict';

const DEG = Math.PI / 180;

// Estado global compartido por todos los m├│dulos
const App = {
  canvas: null,
  ctx: null,
  cx: 0,
  cy: 0,
  visorRadius: 0,

  state: {
    rotacionBrujula: 0,   // azimut de la vista SUAVIZADO (grados, 0 = Norte)
    pitchOffset: 0,       // elevaci├│n de la vista SUAVIZADA (grados)
    targetRotacion: 0,    // azimut objetivo que fijan sensores / arrastre
    targetElevacion: 0,   // elevaci├│n objetivo que fijan sensores / arrastre
    modeAR: false,        // true = sensores, false = arrastre manual
    observer: { lat: 0, lon: 0, altKm: 0, fixed: false },
    sweepAngle: 0,        // barrido de radar
    selectedStar: null,   // astro fijado por el navegante
    autoPan: false,       // giro autom├ítico hacia el astro (solo modo manual)
  },

  // Suavizado del movimiento (0 = inm├│vil, 1 = sin suavizar / salto directo)
  smooth: 0.16,

  stars: [],
  // Ganchos que llenan los otros m├│dulos
  hooks: { drawSatellites: null, drawGame: null, update: null, updateView: null },
};

/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ CAT├üLOGO DE ESTRELLAS REALES ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
   [nombre, constelaci├│n, RA (horas), Dec (grados), magnitud, distancia (al), clase espectral] */
const SPECTRAL_COLOR = {
  O: '#9fc2ff', B: '#a9c8ff', A: '#e8f2f8', F: '#f7f2dc',
  G: '#f5e28e', K: '#f2b264', M: '#ff8f66',
};

const STAR_CATALOG = [
  ['Sirio', 'Can Mayor', 6.752, -16.716, -1.46, 8.6, 'A'],
  ['Canopus', 'Carina', 6.399, -52.696, -0.74, 310, 'F'],
  ['Rigil Kentaurus', 'Centauro', 14.660, -60.834, -0.27, 4.4, 'G'],
  ['Arcturus', 'Boyero', 14.261, 19.182, -0.05, 37, 'K'],
  ['Vega', 'Lira', 18.616, 38.784, 0.03, 25, 'A'],
  ['Capella', 'Auriga', 5.278, 45.998, 0.08, 43, 'G'],
  ['Rigel', 'Ori├│n', 5.242, -8.202, 0.13, 860, 'B'],
  ['Proci├│n', 'Can Menor', 7.655, 5.225, 0.34, 11.5, 'F'],
  ['Achernar', 'Er├¡dano', 1.629, -57.237, 0.46, 139, 'B'],
  ['Betelgeuse', 'Ori├│n', 5.919, 7.407, 0.50, 548, 'M'],
  ['Hadar', 'Centauro', 14.064, -60.373, 0.61, 390, 'B'],
  ['Altair', '├üguila', 19.846, 8.868, 0.77, 16.7, 'A'],
  ['Acrux', 'Cruz del Sur', 12.443, -63.099, 0.76, 320, 'B'],
  ['Aldebar├ín', 'Tauro', 4.599, 16.509, 0.86, 65, 'K'],
  ['Antares', 'Escorpi├│n', 16.490, -26.432, 0.96, 550, 'M'],
  ['Spica', 'Virgo', 13.420, -11.161, 0.97, 250, 'B'],
  ['P├│lux', 'G├⌐minis', 7.755, 28.026, 1.14, 34, 'K'],
  ['Fomalhaut', 'Pez Austral', 22.961, -29.622, 1.16, 25, 'A'],
  ['Deneb', 'Cisne', 20.690, 45.280, 1.25, 2600, 'A'],
  ['Mimosa', 'Cruz del Sur', 12.795, -59.689, 1.25, 280, 'B'],
  ['R├⌐gulo', 'Leo', 10.139, 11.967, 1.35, 79, 'B'],
