'use strict';

const LOCK_RADIUS_PX = 15;    // distancia de colisi├│n con la mira
const SYNC_SECONDS = 5;       // duraci├│n de la sincronizaci├│n

const Game = {
  progress: 0,          // 0..1
  target: null,         // sat├⌐lite en la mira
  terminalOpen: false,
  intercepted: new Set(),
};

const PIRATE_MESSAGES = {
  ISS: [
    '┬╗┬╗ BOT├ìN DETECTADO EN COORDENADAS 19.4326┬░N, 99.1332┬░O ┬½┬½',
    'LA TRIPULACI├ôN DE LA ZARYA ESCONDE 400 TONELADAS DE ORO',
    'ESTELAR. CONTRASE├æA DEL COFRE: "KEPLER-TIENE-LA-LLAVE".',
    'FIRMADO: EL CORSARIO ORBITAL, 51.6┬░ DE INCLINACI├ôN Y SIN LEY.',
  ],
  HUBBLE: [
    '┬╗┬╗ DIARIO DEL VIG├ìA DEL HUBBLE ΓÇö ENTRADA 20580 ┬½┬½',
    'HE VISTO GALAXIAS QUE NING├ÜN PIRATA SAQUEAR├ü JAM├üS.',
