    // Tambi├⌐n se pliega tocando la cabecera
    const head = panel.querySelector('.map-head');
    if (head) head.addEventListener('click', (e) => {
      if (e.target.id !== 'map-toggle') togglePanel();
    });

    computeTrack();
    requestAnimationFrame(loop);
  }

  function togglePanel() {
    panel.classList.toggle('collapsed');
    const toggle = document.getElementById('map-toggle');
    if (toggle) toggle.textContent = panel.classList.contains('collapsed') ? 'Γû╕' : 'Γû╛';
  }

  /* ΓöÇΓöÇ Bucle de dibujo ΓöÇΓöÇ */
  function loop(t) {
    requestAnimationFrame(loop);
    if (!ctx || panel.classList.contains('collapsed')) return;

    const time = t / 1000;
    if (Date.now() - lastTrackCalc > 15000) computeTrack();

    drawOcean();
    drawGraticule();
    drawLand();
    drawTerminator();
    drawFootprints();
    drawTrack();
    drawObserver();
    drawSats(time);
    updateReadout();
  }

  function drawOcean() {
    const g = ctx.createLinearGradient(0, 0, 0, H);
    g.addColorStop(0, '#08171b');
    g.addColorStop(0.5, '#0a2029');
    g.addColorStop(1, '#08171b');
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, W, H);
  }

  function drawGraticule() {
    ctx.strokeStyle = 'rgba(212, 166, 56, 0.16)';
    ctx.lineWidth = 0.5;
    ctx.beginPath();
    for (let lon = -180; lon <= 180; lon += 30) {
      const x = (lon + 180) / 360 * W;
      ctx.moveTo(x, 0); ctx.lineTo(x, H);
    }
    for (let lat = -60; lat <= 60; lat += 30) {
      const y = (90 - lat) / 180 * H;
      ctx.moveTo(0, y); ctx.lineTo(W, y);
    }
    ctx.stroke();

    // ecuador remarcado
    ctx.strokeStyle = 'rgba(212, 166, 56, 0.32)';
    ctx.lineWidth = 0.8;
    ctx.beginPath();
    ctx.moveTo(0, H / 2); ctx.lineTo(W, H / 2);
    ctx.stroke();
  }

  function drawLand() {
    ctx.lineJoin = 'round';
    for (const poly of LAND) {
      ctx.beginPath();
      for (let i = 0; i < poly.length; i++) {
        const p = project(poly[i][0], poly[i][1]);
        if (i === 0) ctx.moveTo(p.x, p.y);
        else ctx.lineTo(p.x, p.y);
      }
      ctx.closePath();
      ctx.fillStyle = 'rgba(90, 74, 34, 0.55)';
      ctx.fill();
      ctx.strokeStyle = 'rgba(212, 166, 56, 0.65)';
      ctx.lineWidth = 0.8;
      ctx.stroke();
    }
  }

  /* ΓöÇΓöÇ Sombra nocturna aproximada (terminador d├¡a/noche) ΓöÇΓöÇ */
  function drawTerminator() {
    const now = new Date();
    // Longitud subsolar Γëê -15┬░ por cada hora UTC desde mediod├¡a
    const utcHours = now.getUTCHours() + now.getUTCMinutes() / 60 + now.getUTCSeconds() / 3600;
    const sunLon = -15 * (utcHours - 12);
    // Declinaci├│n solar aproximada seg├║n el d├¡a del a├▒o
    const dayOfYear = Math.floor((now - new Date(Date.UTC(now.getUTCFullYear(), 0, 0))) / 86400000);
    const sunLat = 23.44 * Math.sin((360 / 365) * (dayOfYear - 81) * Math.PI / 180);

    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, W, H);
    ctx.clip();
    ctx.fillStyle = 'rgba(3, 8, 12, 0.42)';
    ctx.beginPath();
    let started = false;
    for (let lon = -180; lon <= 180; lon += 2) {
      const H0 = (lon - sunLon) * Math.PI / 180;
      const lat = Math.atan(-Math.cos(H0) / Math.tan(sunLat * Math.PI / 180)) * 180 / Math.PI;
      const p = project(lon, lat);
      if (!started) { ctx.moveTo(p.x, p.y); started = true; } else ctx.lineTo(p.x, p.y);
    }
    if (sunLat >= 0) { ctx.lineTo(W, 0); ctx.lineTo(0, 0); }
    else { ctx.lineTo(W, H); ctx.lineTo(0, H); }
    ctx.closePath();
    ctx.fill();
    ctx.restore();
  }

  /* ΓöÇΓöÇ Punto de destino sobre la esfera a distancia angular c y rumbo brg ΓöÇΓöÇ */
  function destPoint(latDeg, lonDeg, c, brgDeg) {
    const lat1 = latDeg * D2R, lon1 = lonDeg * D2R, brg = brgDeg * D2R;
    const lat2 = Math.asin(Math.sin(lat1) * Math.cos(c) + Math.cos(lat1) * Math.sin(c) * Math.cos(brg));
    const lon2 = lon1 + Math.atan2(
      Math.sin(brg) * Math.sin(c) * Math.cos(lat1),
      Math.cos(c) - Math.sin(lat1) * Math.sin(lat2),
    );
    let lon = lon2 / D2R;
    lon = ((lon + 180) % 360 + 360) % 360 - 180;
    return { lat: lat2 / D2R, lon };
  }

  /* ΓöÇΓöÇ Huella de cobertura: regi├│n desde la que el sat├⌐lite est├í sobre
     el horizonte (radio angular = acos(Re / (Re + altitud))) ΓöÇΓöÇ */
  function drawFootprints() {
    if (typeof SATELLITES === 'undefined') return;
    for (const sat of SATELLITES) {
      if (!sat.altKm || sat.lonDeg === undefined) continue;
      const c = Math.acos(EARTH_R / (EARTH_R + sat.altKm));  // radio angular (rad)

      const pts = [];
      let wraps = false;
      let prevX = null;
      for (let b = 0; b <= 360; b += 6) {
        const q = destPoint(sat.latDeg, sat.lonDeg, c, b);
        const p = project(q.lon, q.lat);
        if (prevX !== null && Math.abs(p.x - prevX) > W / 2) wraps = true;
        prevX = p.x;
        pts.push(p);
      }

      // relleno tenue solo si la huella no cruza el meridiano ┬▒180 (evita artefactos)
      if (!wraps) {
        ctx.beginPath();
        pts.forEach((p, i) => (i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y)));
        ctx.closePath();
        ctx.fillStyle = sat.color;
        ctx.globalAlpha = 0.07;
        ctx.fill();
      }

      // contorno (partido en el salto de meridiano)
      ctx.strokeStyle = sat.color;
      ctx.globalAlpha = 0.3;
      ctx.lineWidth = 1;
      ctx.beginPath();
      let prev = null;
      for (const p of pts) {
        if (prev && Math.abs(p.x - prev.x) > W / 2) { ctx.stroke(); ctx.beginPath(); prev = null; }
        if (!prev) ctx.moveTo(p.x, p.y); else ctx.lineTo(p.x, p.y);
        prev = p;
      }
      ctx.stroke();
      ctx.globalAlpha = 1;
    }
  }

  /* ΓöÇΓöÇ Marcador del observador (nav├¡o) seg├║n la geolocalizaci├│n ΓöÇΓöÇ */
  function drawObserver() {
    if (typeof App === 'undefined') return;
    const o = App.state && App.state.observer;
    if (!o || !o.fixed) return;
    const p = project(o.lon, o.lat);

    // diamante de lat├│n
    ctx.save();
    ctx.translate(p.x, p.y);
    ctx.fillStyle = '#d4a638';
    ctx.strokeStyle = '#050a0e';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, -4); ctx.lineTo(4, 0); ctx.lineTo(0, 4); ctx.lineTo(-4, 0);
    ctx.closePath();
    ctx.fill(); ctx.stroke();
    ctx.restore();

    ctx.font = "10px 'VT323', monospace";
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.fillStyle = '#d8c9a3';
    ctx.shadowColor = 'rgba(0,0,0,0.9)';
    ctx.shadowBlur = 2;
    ctx.fillText('NAV├ìO', p.x, p.y + 4);
    ctx.shadowBlur = 0;
  }

  /* ΓöÇΓöÇ Traza de tierra de la ISS (l├¡nea punteada, con corte en ┬▒180) ΓöÇΓöÇ */
  function drawTrack() {
    if (track.length < 2) return;
    ctx.strokeStyle = 'rgba(57, 255, 20, 0.55)';
    ctx.lineWidth = 1;
    ctx.setLineDash([2, 3]);
    ctx.beginPath();
    let prev = null;
    for (const pt of track) {
      if (!pt) { prev = null; continue; }
      const p = project(pt.lon, pt.lat);
      if (prev && Math.abs(p.x - prev.x) > W / 2) prev = null;  // salto de meridiano
      if (!prev) ctx.moveTo(p.x, p.y);
      else ctx.lineTo(p.x, p.y);
      prev = p;
    }
    ctx.stroke();
    ctx.setLineDash([]);
  }

  /* ΓöÇΓöÇ Puntos subsat├⌐lite parpadeantes + enlace de visibilidad ΓöÇΓöÇ */
  function drawSats(time) {
    if (typeof SATELLITES === 'undefined') return;
    const obs = (typeof App !== 'undefined' && App.state) ? App.state.observer : null;

    for (const sat of SATELLITES) {
      if (sat.lonDeg === undefined) continue;
      const p = project(sat.lonDeg, sat.latDeg);
      const isISS = sat.name === ISS_NAME;

      // enlace nav├¡o Γåö sat├⌐lite cuando est├í sobre el horizonte del observador
      if (sat.visible && obs && obs.fixed) {
        const po = project(obs.lon, obs.lat);
        if (Math.abs(po.x - p.x) < W / 2) {
          ctx.strokeStyle = sat.color;
          ctx.globalAlpha = 0.5;
          ctx.lineWidth = 0.8;
          ctx.setLineDash([1, 2]);
          ctx.beginPath();
          ctx.moveTo(po.x, po.y);
          ctx.lineTo(p.x, p.y);
          ctx.stroke();
          ctx.setLineDash([]);
          ctx.globalAlpha = 1;
        }
      }

      const blink = 0.5 + 0.5 * Math.sin(time * 6);
      const pulse = (time % 1.5) / 1.5;

      // anillo de pulso expansivo
      ctx.strokeStyle = sat.color;
      ctx.globalAlpha = (1 - pulse) * 0.7;
      ctx.lineWidth = 1.2;
      ctx.beginPath();
      ctx.arc(p.x, p.y, 2 + pulse * (isISS ? 11 : 7), 0, Math.PI * 2);
      ctx.stroke();

      // punto central intermitente
      ctx.globalAlpha = 0.55 + 0.45 * blink;
      ctx.fillStyle = sat.color;
      ctx.shadowColor = sat.color;
      ctx.shadowBlur = 8;
      ctx.beginPath();
      ctx.arc(p.x, p.y, isISS ? 3.2 : 2.4, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
      ctx.globalAlpha = 1;

      // etiqueta
      ctx.font = "11px 'VT323', monospace";
      ctx.textAlign = 'left';
      ctx.textBaseline = 'bottom';
      ctx.fillStyle = sat.color;
      ctx.shadowColor = 'rgba(0,0,0,0.9)';
      ctx.shadowBlur = 2;
      let lx = p.x + 5;
      if (lx > W - 34) { ctx.textAlign = 'right'; lx = p.x - 5; }
      ctx.fillText(sat.name, lx, p.y - 3);
      ctx.shadowBlur = 0;
    }
  }

  function fmt(v, pos, neg) {
    return Math.abs(v).toFixed(1) + '┬░' + (v >= 0 ? pos : neg);
  }

  function updateReadout() {
    if (!readout) return;
    const sat = issSat();
    if (!sat || sat.lonDeg === undefined) return;
    const coords = `ISS  ${fmt(sat.latDeg, 'N', 'S')}  ${fmt(sat.lonDeg, 'E', 'O')}`;
    const alt = sat.altKm ? ` ┬╖ ${Math.round(sat.altKm)}km` : '';
    readout.textContent = coords + alt + (sat.visible ? ' Γû▓' : '');
    readout.classList.toggle('visible-now', !!sat.visible);
  }

  document.addEventListener('DOMContentLoaded', initMap);
})();
